 234→const CanvasEditor = ({title, onCloseOnSave, addUploadedImagePath, initialCanvasDoc = null, remixSource = null}) => {
 235→    const {session, user} = useAuth();
 236→    const queryClient = useQueryClient();
 237→    const shellRef = useRef(null);
 238→    const ambientLightRef = useRef(null);
 239→    const stageFrameRef = useRef(null);
 240→    const stageRef = useRef(null);
 241→    const hasHydratedInitialDocRef = useRef(false);
 242→    const snippetInputRef = useRef(null);
 243→    const doodlePointsRef = useRef([]);
 244→    const viewportRef = useRef({scale: 1, x: 0, y: 0});
 245→    const pinchStateRef = useRef({isActive: false, lastDistance: 0, lastCenter: null});
 246→    const [shellWidth, setShellWidth] = useState(CANVAS_MAX_WIDTH);
 247→
 248→    const [activeTool, setActiveTool] = useState("select");
 249→    const [isSnippetComposerOpen, setIsSnippetComposerOpen] = useState(false);
 250→    const [snippetInput, setSnippetInput] = useState("");
 251→    const [selectedObject, setSelectedObject] = useState(null);
 252→    const [draggingObject, setDraggingObject] = useState(null);
 253→    const [isSending, setIsSending] = useState(false);
 254→    const [isUploadingImage, setIsUploadingImage] = useState(false);
 255→    const [doodleColor, setDoodleColor] = useState(DEFAULT_DOODLE_COLOR);
 256→    const [doodleSize, setDoodleSize] = useState(2.8);
 257→    const [isDrawing, setIsDrawing] = useState(false);
 258→    const [currentDoodlePoints, setCurrentDoodlePoints] = useState([]);
 259→    const [canvasMeta, setCanvasMeta] = useState({
 260→        aspectRatio: "1:1",
 261→        gridEnabled: true,
 262→        snapEnabled: true,
 263→        theme: "light"
 264→    });
 265→    const [snippets, setSnippets] = useState([]);
 266→    const [images, setImages] = useState([]);
 267→    const [doodles, setDoodles] = useState([]);
 268→    const [viewport, setViewport] = useState({scale: 1, x: 0, y: 0});
 269→    const [isMobileViewport, setIsMobileViewport] = useState(false);
 270→    const [isMobileDockOpen, setIsMobileDockOpen] = useState(false);
 271→    const [mobileDoodlePanelDismissed, setMobileDoodlePanelDismissed] = useState(false);
 272→    const [animatingRemovalId, setAnimatingRemovalId] = useState(null);
 273→    const [doodleRedoStack, setDoodleRedoStack] = useState([]);
 274→    const multiTapRef = useRef({fingerCount: 0, timestamp: 0});
 275→    const longPressRef = useRef(null);
 276→    const [pieMenu, setPieMenu] = useState({isOpen: false, position: null, items: []});
 277→
 278→    const updateSnippet = (snippetId, updater) => {
 279→        setSnippets((prev) => prev.map((snippet) => {
 280→            if(snippet.id !== snippetId){
 281→                return snippet;
 282→            }
 283→            const nextValue = typeof updater === "function" ? updater(snippet) : updater;
 284→            return {...snippet, ...nextValue};
 285→        }));
 286→    };
 287→
 288→    const updateImage = (imageId, updater) => {
 289→        setImages((prev) => prev.map((image) => {
 290→            if(image.id !== imageId){
 291→                return image;
 292→            }
 293→            const nextValue = typeof updater === "function" ? updater(image) : updater;
 294→            return {...image, ...nextValue};
 295→        }));
 296→    };
 297→
 298→    useEffect(() => {
 299→        if(hasHydratedInitialDocRef.current || !initialCanvasDoc){
 300→            return;
 301→        }
 302→
 303→        const parsedDoc = parseCanvasDoc(initialCanvasDoc);
 304→        setCanvasMeta((prev) => ({
 305→            ...prev,
 306→            aspectRatio: parsedDoc?.meta?.aspectRatio === "4:5" ? "4:5" : "1:1",
 307→            gridEnabled: Boolean(parsedDoc?.meta?.gridEnabled),
 308→            theme: parsedDoc?.meta?.theme === "dark" ? "dark" : "light"
 309→        }));
 310→        setSnippets((parsedDoc?.snippets || []).map((snippet) => ({
 311→            ...snippet,
 312→            id: snippet.id || createId("snippet"),
 313→            fontStyle: getLegacyFontStyle(snippet.fontStyle),
 314→            zIndex: Number.isFinite(snippet?.zIndex) ? snippet.zIndex : 0
 315→        })));
 316→        setImages((parsedDoc?.images || []).map((image) => ({
 317→            ...image,
 318→            id: image.id || createId("image"),
 319→            zIndex: Number.isFinite(image?.zIndex) ? image.zIndex : 0
 320→        })));
 321→        setDoodles((parsedDoc?.doodles || []).map((doodle) => ({
 322→            ...doodle,
 323→            id: doodle.id || createId("doodle"),
 324→            points: sanitizeNormalizedPoints(doodle.points)
 325→        })));
 326→        hasHydratedInitialDocRef.current = true;
 327→    }, [initialCanvasDoc]);
 328→
 329→    useEffect(() => {
 330→        const getContentWidth = () => {
 331→            const element = shellRef.current;
 332→            if(!element){
 333→                return CANVAS_MAX_WIDTH;
 334→            }
 335→            const computedStyle = getComputedStyle(element);
 336→            const paddingLeft = parseFloat(computedStyle.paddingLeft) || 0;
 337→            const paddingRight = parseFloat(computedStyle.paddingRight) || 0;
 338→            return Math.max(0, element.clientWidth - paddingLeft - paddingRight);
 339→        };
 340→
 341→        const updateShellWidth = () => {
 342→            setShellWidth(getContentWidth());
 343→        };
 344→
 345→        updateShellWidth();
 346→        window.addEventListener("resize", updateShellWidth);
 347→
 348→        let resizeObserver = null;
 349→        if(typeof ResizeObserver !== "undefined" && shellRef.current){
 350→            resizeObserver = new ResizeObserver(updateShellWidth);
 351→            resizeObserver.observe(shellRef.current);
 352→        }
 353→
 354→        return () => {
 355→            window.removeEventListener("resize", updateShellWidth);
 356→            if(resizeObserver){
 357→                resizeObserver.disconnect();
 358→            }
 359→        };
 360→    }, []);
 361→
 362→    useEffect(() => {
 363→        const mediaQuery = window.matchMedia(`(max-width: ${MOBILE_BREAKPOINT}px)`);
 364→        const syncViewport = () => setIsMobileViewport(mediaQuery.matches);
 365→        syncViewport();
 366→
 367→        if(typeof mediaQuery.addEventListener === "function"){
 368→            mediaQuery.addEventListener("change", syncViewport);
 369→            return () => mediaQuery.removeEventListener("change", syncViewport);
 370→        }
 371→
 372→        mediaQuery.addListener(syncViewport);
 373→        return () => mediaQuery.removeListener(syncViewport);
 374→    }, []);
 375→
 376→    useEffect(() => {
 377→        if(isMobileViewport){
 378→            setIsMobileDockOpen(false);
 379→            return;
 380→        }
 381→        setIsMobileDockOpen(true);
 382→    }, [isMobileViewport]);
 383→
 384→    useEffect(() => {
 385→        if(!isSnippetComposerOpen){
 386→            return;
 387→        }
 388→        const frame = window.requestAnimationFrame(() => snippetInputRef.current?.focus());
 389→        return () => window.cancelAnimationFrame(frame);
 390→    }, [isSnippetComposerOpen]);
 391→
 392→    useEffect(() => {
 393→        if(activeTool !== "doodle"){
 394→            doodlePointsRef.current = [];
 395→            setCurrentDoodlePoints([]);
 396→            setIsDrawing(false);
 397→            setMobileDoodlePanelDismissed(false);
 398→        }
 399→    }, [activeTool]);
 400→
 401→    const viewportWidth = useMemo(() => Math.max(280, Math.min(CANVAS_MAX_WIDTH, shellWidth)), [shellWidth]);
 402→    const viewportHeight = getStageHeight(viewportWidth, canvasMeta.aspectRatio);
 403→    const stageWidth = CANVAS_MAX_WIDTH;
 404→    const stageHeight = getStageHeight(stageWidth, canvasMeta.aspectRatio);
 405→    const fitScale = viewportWidth > 0 ? viewportWidth / stageWidth : 1;
 406→    const fitOffsetX = (viewportWidth - stageWidth * fitScale) / 2;
 407→    const fitOffsetY = (viewportHeight - stageHeight * fitScale) / 2;
 408→
 409→    const updateViewport = (updater) => {
 410→        setViewport((prev) => {
 411→            const nextValue = typeof updater === "function" ? updater(prev) : updater;
 412→            const constrained = constrainViewport(nextValue, viewportWidth, viewportHeight);
 413→            viewportRef.current = constrained;
 414→            return constrained;
 415→        });
 416→    };
 417→
 418→    useEffect(() => {
 419→        viewportRef.current = viewport;
 420→    }, [viewport]);
 421→
 422→    useEffect(() => {
 423→        setViewport((prev) => constrainViewport(prev, viewportWidth, viewportHeight));
 424→    }, [viewportWidth, viewportHeight]);
 425→
 426→    useEffect(() => {
 427→        const safePixelRatio = clamp(window.devicePixelRatio || 1, 1, 2.5);
 428→        const stage = stageRef.current;
 429→        if(!stage){
 430→            return;
 431→        }
 432→
 433→        const previousRatio = Konva.pixelRatio;
 434→        Konva.pixelRatio = safePixelRatio;
 435→        stage.getLayers().forEach((layer) => {
 436→            const canvas = layer?.getCanvas?.();
 437→            if(canvas?.setPixelRatio){
 438→                canvas.setPixelRatio(safePixelRatio);
 439→            }
 440→        });
 441→        stage.batchDraw();
 442→        return () => {
 443→            Konva.pixelRatio = previousRatio;
 444→        };
 445→    }, [viewportWidth, viewportHeight]);
 446→
 447→    const getNextZIndex = () => {
 448→        const allZ = [
 449→            ...snippets.map((snippet) => snippet.zIndex || 0),
 450→            ...images.map((image) => image.zIndex || 0)
 451→        ];
 452→        return allZ.length ? Math.max(...allZ) + 1 : 0;
 453→    };
 454→
 455→    const sortedObjects = useMemo(() => buildSortedCanvasObjects(snippets, images), [snippets, images]);
 456→
 457→    const selectedSnippet = selectedObject?.kind === "snippet"
 458→        ? snippets.find((snippet) => snippet.id === selectedObject.id) || null
 459→        : null;
 460→    const canEditObjects = activeTool === "select";
 461→    const isDoodleMode = activeTool === "doodle";
 462→    const shouldPreventTouchDefault = isDoodleMode;
 463→    const hasCanvasContent = snippets.length > 0 || images.length > 0 || doodles.length > 0;
 464→    const showDoodlePanel = isDoodleMode && !(isMobileViewport && mobileDoodlePanelDismissed);
 465→    const showContextPanel = isSnippetComposerOpen || showDoodlePanel || (selectedObject && activeTool === "select");
 466→
 467→    const addSnippet = () => {
 468→        const trimmed = snippetInput.trim();
 469→        if(!trimmed){
 470→            return;
 471→        }
 472→
 473→        const jitter = randomPlacement();
 474→        const snippet = {
 475→            id: createId("snippet"),
 476→            text: trimmed,
 477→            x: clamp(0.16 + jitter.xOffset, 0.02, 0.82),
 478→            y: clamp(0.2 + jitter.yOffset, 0.02, 0.82),
 479→            rotation: jitter.rotation,
 480→            fontStyle: "serif",
 481→            scaleX: 1,
 482→            sizeScale: 1,
 483→            zIndex: getNextZIndex()
 484→        };
 485→        setSnippets((prev) => [...prev, snippet]);
 486→        setSelectedObject({kind: "snippet", id: snippet.id});
 487→        setSnippetInput("");
 488→        setIsSnippetComposerOpen(false);
 489→        setActiveTool("select");
 490→    };
 491→
 492→    const addImageFromFile = () => {
 493→        const input = document.createElement("input");
 494→        input.type = "file";
 495→        input.accept = "image/*";
 496→        input.onchange = async(event) => {
 497→            const file = event.target.files?.[0];
 498→            if(!file){
 499→                return;
 500→            }
 501→
 502→            setIsUploadingImage(true);
 503→            try {
 504→                const dimensions = await new Promise((resolve) => {
 505→                    const tempImg = new window.Image();
 506→                    const objectUrl = URL.createObjectURL(file);
 507→                    tempImg.onload = () => {
 508→                        resolve({
 509→                            width: tempImg.naturalWidth || 1200,
 510→                            height: tempImg.naturalHeight || 800
 511→                        });
 512→                        URL.revokeObjectURL(objectUrl);
 513→                    };
 514→                    tempImg.onerror = () => {
 515→                        resolve({width: 1200, height: 800});
 516→                        URL.revokeObjectURL(objectUrl);
 517→                    };
 518→                    tempImg.src = objectUrl;
 519→                });
 520→
 521→                const formdata = new FormData();
 522→                formdata.append("image", file);
 523→                const uploaded = await saveJournalImage(session?.access_token, formdata);
 524→                const imageSrc = uploaded?.img_url;
 525→                if(!imageSrc){
 526→                    return;
 527→                }
 528→
 529→                const filePath = imageSrc.split("/journal-images/").pop();
 530→                if(filePath && addUploadedImagePath){
 531→                    addUploadedImagePath(filePath);
 532→                }
 533→
 534→                const ratio = dimensions.width / dimensions.height;
 535→                const baseWidth = 0.34;
 536→                const rawHeight = ratio > 0 ? baseWidth / ratio : 0.24;
 537→                const imgJitter = randomPlacement();
 538→                const imageObject = {
 539→                    id: createId("image"),
 540→                    src: imageSrc,
 541→                    x: clamp(0.18 + imgJitter.xOffset, 0.02, 0.82),
 542→                    y: clamp(0.24 + imgJitter.yOffset, 0.02, 0.82),
 543→                    width: clamp(baseWidth, 0.14, 0.8),
 544→                    height: clamp(rawHeight, 0.12, 0.8),
 545→                    rotation: imgJitter.rotation,
 546→                    scaleX: 1,
 547→                    zIndex: getNextZIndex()
